  ('social-worker-moex-06537', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'essay', '請舉例說明實驗研究可以運用在實務工作的那些面向？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06538', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '量化和質化研究者雖有一些共通之處，但往往在研究設計的議題上出現差異，下列敘述何者正確？ 量化研究的步驟均為特別設計，極少採用複製 質化研究中理論大多具有因果關係且是演繹的 量化研究中理論可以是因果或非因果的，通常是歸納的 質化研究者在蒐集資料的過程中，就會開始發掘理論了', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06539', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於焦點團體法，下列敘述何者錯誤？ 參與者是根據與討論主題有關的人，透過隨機抽樣選取的 可運用在評估一個社區是否真的需要一項新的社會方案或社會服務 雖然在通則化有一定的風險，但其優點是費用低廉、快速產生結果、調查有彈性 是發展往後調查研究中問卷項目好用的工具', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
